import requests
import json
from typing import List, Dict, Optional
from requests.auth import HTTPBasicAuth
import sys


class RabbitMQConfigurator:
    def __init__(self, host: str = "localhost", port: int = 15672, 
                 username: str = "guest", password: str = "guest"):
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(username, password)
        self.headers = {"Content-Type": "application/json"}
    
    def create_vhost(self, vhost_name: str) -> bool:
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.put(url, auth=self.auth, headers=self.headers)
        
        if response.status_code in [201, 204]:
            print(f"✓ Virtual host '{vhost_name}' created successfully")
            return True
        elif response.status_code == 409:
            print(f"⚠ Virtual host '{vhost_name}' already exists")
            return True
        else:
            print(f"✗ Failed to create vhost '{vhost_name}': {response.status_code} - {response.text}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        url = f"{self.base_url}/vhosts/{vhost_name}"
        response = requests.delete(url, auth=self.auth)
        
        if response.status_code == 204:
            print(f"✓ Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete vhost '{vhost_name}': {response.status_code}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        url = f"{self.base_url}/vhosts"
        response = requests.get(url, auth=self.auth)
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"✗ Failed to list vhosts: {response.status_code}")
            return []
    
    def create_user(self, username: str, password: str, tags: str = "") -> bool:
        url = f"{self.base_url}/users/{username}"
        data = {
            "password": password,
            "tags": tags
        }
        response = requests.put(url, auth=self.auth, headers=self.headers, 
                              data=json.dumps(data))
        
        if response.status_code in [201, 204]:
            print(f"✓ User '{username}' created successfully with tags: {tags}")
            return True
        else:
            print(f"✗ Failed to create user '{username}': {response.status_code} - {response.text}")
            return False
    
    def delete_user(self, username: str) -> bool:
        url = f"{self.base_url}/users/{username}"
        response = requests.delete(url, auth=self.auth)
        
        if response.status_code == 204:
            print(f"✓ User '{username}' deleted successfully")
            return True
        else:
            print(f"✗ Failed to delete user '{username}': {response.status_code}")
            return False
    
    def list_users(self) -> List[Dict]:
        url = f"{self.base_url}/users"
        response = requests.get(url, auth=self.auth)
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"✗ Failed to list users: {response.status_code}")
            return []
    
    def set_permissions(self, username: str, vhost: str, 
                       configure: str = ".*", write: str = ".*", 
                       read: str = ".*") -> bool:
        url = f"{self.base_url}/permissions/{vhost}/{username}"
        data = {
            "configure": configure,
            "write": write,
            "read": read
        }
        response = requests.put(url, auth=self.auth, headers=self.headers, 
                              data=json.dumps(data))
        
        if response.status_code in [201, 204]:
            print(f"✓ Permissions set for user '{username}' on vhost '{vhost}'")
            print(f"  Configure: {configure}, Write: {write}, Read: {read}")
            return True
        else:
            print(f"✗ Failed to set permissions: {response.status_code} - {response.text}")
            return False
    
    def get_permissions(self, username: str, vhost: str) -> Optional[Dict]:
        url = f"{self.base_url}/permissions/{vhost}/{username}"
        response = requests.get(url, auth=self.auth)
        
        if response.status_code == 200:
            return response.json()
        else:
            return None
    
    def list_permissions(self, vhost: Optional[str] = None) -> List[Dict]:
        if vhost:
            url = f"{self.base_url}/vhosts/{vhost}/permissions"
        else:
            url = f"{self.base_url}/permissions"
        
        response = requests.get(url, auth=self.auth)
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"✗ Failed to list permissions: {response.status_code}")
            return []
    
    def clear_permissions(self, username: str, vhost: str) -> bool:
        url = f"{self.base_url}/permissions/{vhost}/{username}"
        response = requests.delete(url, auth=self.auth)
        
        if response.status_code == 204:
            print(f"✓ Permissions cleared for user '{username}' on vhost '{vhost}'")
            return True
        else:
            print(f"✗ Failed to clear permissions: {response.status_code}")
            return False
    
    def set_topic_permissions(self, username: str, vhost: str, exchange: str,
                             write: str = ".*", read: str = ".*") -> bool:
        url = f"{self.base_url}/topic-permissions/{vhost}/{username}"
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        response = requests.put(url, auth=self.auth, headers=self.headers,
                              data=json.dumps(data))
        
        if response.status_code in [201, 204]:
            print(f"✓ Topic permissions set for user '{username}' on vhost '{vhost}' for exchange '{exchange}'")
            return True
        else:
            print(f"✗ Failed to set topic permissions: {response.status_code} - {response.text}")
            return False
    
    def configure_multi_tenant_setup(self, tenants: List[Dict]) -> bool:
        success = True
        
        for tenant in tenants:
            tenant_name = tenant.get("name")
            vhost_name = tenant.get("vhost", tenant_name)
            users = tenant.get("users", [])
            
            print(f"\n{'='*60}")
            print(f"Configuring tenant: {tenant_name}")
            print(f"{'='*60}")
            
            if not self.create_vhost(vhost_name):
                success = False
                continue
            
            for user in users:
                username = user.get("username")
                password = user.get("password")
                tags = user.get("tags", "")
                permissions = user.get("permissions", {})
                
                if not self.create_user(username, password, tags):
                    success = False
                    continue
                
                configure = permissions.get("configure", ".*")
                write = permissions.get("write", ".*")
                read = permissions.get("read", ".*")
                
                if not self.set_permissions(username, vhost_name, configure, write, read):
                    success = False
        
        return success
    
    def create_exchange(self, vhost: str, exchange_name: str, 
                       exchange_type: str = "direct", durable: bool = True,
                       auto_delete: bool = False) -> bool:
        url = f"{self.base_url}/exchanges/{vhost}/{exchange_name}"
        data = {
            "type": exchange_type,
            "durable": durable,
            "auto_delete": auto_delete
        }
        response = requests.put(url, auth=self.auth, headers=self.headers,
                              data=json.dumps(data))
        
        if response.status_code in [201, 204]:
            print(f"✓ Exchange '{exchange_name}' created in vhost '{vhost}'")
            return True
        else:
            print(f"✗ Failed to create exchange: {response.status_code} - {response.text}")
            return False
    
    def create_queue(self, vhost: str, queue_name: str, durable: bool = True,
                    auto_delete: bool = False) -> bool:
        url = f"{self.base_url}/queues/{vhost}/{queue_name}"
        data = {
            "durable": durable,
            "auto_delete": auto_delete
        }
        response = requests.put(url, auth=self.auth, headers=self.headers,
                              data=json.dumps(data))
        
        if response.status_code in [201, 204]:
            print(f"✓ Queue '{queue_name}' created in vhost '{vhost}'")
            return True
        else:
            print(f"✗ Failed to create queue: {response.status_code} - {response.text}")
            return False
    
    def get_overview(self) -> Optional[Dict]:
        url = f"{self.base_url}/overview"
        response = requests.get(url, auth=self.auth)
        
        if response.status_code == 200:
            return response.json()
        else:
            return None


